#!/usr/bin/env bash## KAVACH — one-shot dashboard launcher (no tmux/screen required).## Fully detaches every process (nohup, disown, all fds redirected including# stdin) so nothing is tied to this terminal's controlling tty. The script# launches everything, prints status, and EXITS — handing your terminal# back immediately. Servers keep running after the script returns.## Usage:#   chmod +x scripts/start_dashboard.sh#   ./scripts/start_dashboard.sh## Stop everything later with:#   ./scripts/stop_dashboard.shset -uo pipefailcd "$(dirname "$0")/.."   # repo root, regardless of where this is called fromSANDBOX_PORT=8001OPS_PORT=3000ATTACK_INTERVAL_S=25PIDFILE=/tmp/kavach_pids.txtecho "=== KAVACH Dashboard Launcher (detached mode) ==="echo ""# ── 0. Sanity checks ────────────────────────────────────────────────if [ ! -f ".env" ]; then    echo "[!] No .env found. Copying .env.example — edit it with your LLM endpoint if needed."    cp .env.example .envfiif ! python3 -c "import fastapi, uvicorn" 2>/dev/null; then    echo "[*] Installing Python dependencies..."    pip install -r requirements.txt --break-system-packages -qfi# Clear any PIDs from a previous run so stop_dashboard.sh doesn't try to# kill processes that no longer exist / belong to a different run.> "$PIDFILE"launch() {    # $1 = human label, remaining args = command to run    local label="$1"; shift    if command -v setsid > /dev/null; then        # setsid fully detaches from the controlling terminal at the OS        # level (new session, no tty) — the most robust option, standard        # on every Linux box, no install needed.        setsid "$@" </dev/null > "/tmp/kavach_${label}.log" 2>&1 &    else        nohup "$@" </dev/null > "/tmp/kavach_${label}.log" 2>&1 &    fi    local pid=$!    disown "$pid" 2>/dev/null || disown    echo "$pid" >> "$PIDFILE"    echo "[*] ${label} started (pid ${pid}), log: /tmp/kavach_${label}.log"}# ── 1. Sandbox app ───────────────────────────────────────────────────launch sandbox python3 -m uvicorn src.sandbox_target.app:app \    --port "${SANDBOX_PORT}" --host 0.0.0.0# ── 2. Ops dashboard server ──────────────────────────────────────────launch ops python3 -m uvicorn src.agents.ops_server:ops_app \    --port "${OPS_PORT}" --host 0.0.0.0sleep 3if ! curl -sf "http://localhost:${SANDBOX_PORT}/ping" > /dev/null; then    echo "[!] Sandbox app failed to start. Last 20 lines of log:"    tail -20 /tmp/kavach_sandbox.log    exit 1fiif ! curl -sf "http://localhost:${OPS_PORT}/" > /dev/null; then    echo "[!] Ops server failed to start. Last 20 lines of log:"    tail -20 /tmp/kavach_ops.log    exit 1fiecho "[+] Both servers are up."# ── 3. Point attack.py at the right port ────────────────────────────if grep -q "^TARGET = " scripts/attack.py; then    sed -i "s|^TARGET = .*|TARGET = \"http://localhost:${SANDBOX_PORT}\"|" scripts/attack.py    sed -i "s|^TARGET_LOOPBACK = .*|TARGET_LOOPBACK = \"http://127.0.0.1:${SANDBOX_PORT}\"|" scripts/attack.pyfi# ── 4. Background traffic generator loop ────────────────────────────cat > /tmp/kavach_attack_loop.sh <<EOF#!/usr/bin/env bashwhile true; do    python3 "$(pwd)/scripts/attack.py" >> /tmp/kavach_attack.log 2>&1    sleep ${ATTACK_INTERVAL_S}doneEOFchmod +x /tmp/kavach_attack_loop.shlaunch attack_loop /tmp/kavach_attack_loop.sh# ── 5. Public tunnel ──────────────────────────────────────────────CLOUDFLARED_BIN="$(command -v cloudflared || true)"if [ -z "$CLOUDFLARED_BIN" ] && [ -x "$HOME/.local/bin/cloudflared" ]; then    CLOUDFLARED_BIN="$HOME/.local/bin/cloudflared"fiif [ -n "$CLOUDFLARED_BIN" ]; then    launch tunnel "$CLOUDFLARED_BIN" tunnel --url "http://localhost:${OPS_PORT}"    echo "[*] Waiting for tunnel URL..."    TUNNEL_URL=""    for i in $(seq 1 20); do        TUNNEL_URL=$(grep -oE 'https://[a-zA-Z0-9-]+\.trycloudflare\.com' /tmp/kavach_tunnel.log 2>/dev/null | head -1)        [ -n "$TUNNEL_URL" ] && break        sleep 1    doneelse    echo "[!] cloudflared not found — skipping tunnel. Install it or use an SSH -L tunnel instead."    TUNNEL_URL=""fiecho ""echo "======================================================================"if [ -n "$TUNNEL_URL" ]; then    echo " Dashboard ready:  $TUNNEL_URL"else    echo " No tunnel URL yet — check manually:"    echo "   grep trycloudflare.com /tmp/kavach_tunnel.log"fiecho ""echo " Sandbox app (local):   http://localhost:${SANDBOX_PORT}"echo " Ops dashboard (local): http://localhost:${OPS_PORT}"echo ""echo " Everything is fully detached — safe to keep using this terminal."echo ""echo " Logs:"echo "   tail -f /tmp/kavach_sandbox.log"echo "   tail -f /tmp/kavach_ops.log"echo "   tail -f /tmp/kavach_attack.log"echo "   tail -f /tmp/kavach_tunnel.log"echo ""echo " Check status:  ps -p \$(cat $PIDFILE | tr '\\n' ',' | sed 's/,\$//')"echo " Stop everything:  ./scripts/stop_dashboard.sh"echo "======================================================================"
